CREATE INDEX IF NOT EXISTS idx_garage_vehicle_user_id
    ON garage_vehicle (user_id);
CREATE INDEX IF NOT EXISTS idx_garage_vehicle_vehicle_id
    ON garage_vehicle (vehicle_id);
